// WTTJ returns Next.js SSR with JSON chunks
// Extract job listings from __next_f or rendered HTML
const cheerio = require('cheerio');
const $ = cheerio.load($input.item.json.data);

const jobs = [];

// Try extracting from script tags with JSON
$('script').each((i, el) => {
  const text = $(el).html() || '';
  if (text.includes('__next_f') || text.includes('"offers"') || text.includes('"jobs"')) {
    try {
      // Attempt to parse embedded JSON
      const match = text.match(/"offers":\[([\s\S]*?)\],/);
      if (match) {
        jobs.push(JSON.parse('[' + match[1] + ']'));
      }
    } catch(e) { /* skip */ }
  }
});

// Fallback: extract from HTML structure
$('article, [data-testid="job-card"], .sc-*').each((i, el) => {
  const title = $(el).find('h1, h2, h3, [data-testid="job-title"]').first().text().trim();
  const company = $(el).find('[data-testid="company-name"]').first().text().trim();
  const link = $(el).find('a').first().attr('href') || '';
  if (title) {
    jobs.push({
      title,
      company,
      link: link.startsWith('http') ? link : `https://welcometothejungle.com${link}`,
      source: 'WTTJ',
      scraped_at: new Date().toISOString()
    });
  }
});

return jobs.length > 0 ? jobs : [{ warning: 'Aucune offre trouvée sur WTTJ' }];

// Déduplication par titre + entreprise
const items = $input.all();
const seen = new Set();
const sevenDaysAgo = new Date();
sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);

const filtered = items.filter(item => {
  const title = (item.json.title || '').toLowerCase().trim();
  const company = (item.json.company || item.json.source || '').toLowerCase().trim();
  const key = `${title}|${company}`;

  if (seen.has(key)) return false;
  seen.add(key);

  // Skip entries with warnings
  if (item.json.warning) return false;

  // Skip empty entries
  if (!title) return false;

  return true;
});

// Add source tag and timestamp
filtered.forEach(item => {
  item.json.processed_at = new Date().toISOString();
});

// Sort by source then title
filtered.sort((a, b) => {
  const aSrc = a.json.source || '';
  const bSrc = b.json.source || '';
  if (aSrc !== bSrc) return aSrc.localeCompare(bSrc);
  return (a.json.title || '').localeCompare(b.json.title || '');
});

return filtered;

