// Formater les offres enrichies en HTML pour l'email
const items = $input.all();
const dateStr = new Date().toLocaleDateString('fr-FR', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

let html = `
<!DOCTYPE html>
<html><head><meta charset="utf-8" /></head><body style="font-family: Arial, sans-serif; max-width: 650px; margin: 0 auto;">
<div style="background: #1a1a2e; color: white; padding: 30px; text-align: center;">
  <h1 style="margin:0; font-size: 24px;">Veille Emploi Media</h1>
  <p style="margin:5px 0 0; opacity:0.8;">${dateStr}</p>
</div>
`;

// Group by source
const groups = {};
items.forEach(item => {
  const src = item.json.source || item.json.company || 'Autres';
  if (!groups[src]) groups[src] = [];
  groups[src].push(item.json);
});

for (const [source, offers] of Object.entries(groups)) {
  html += `<h2 style="color: #1a1a2e; border-bottom: 2px solid #e94560; padding-bottom: 8px;">${source}</h2>`;
  html += `<table style="width:100%; border-collapse: collapse;">`;

  offers.forEach(offer => {
    const tags = offer.tags ? offer.tags.map(t => `<span style="background:#eee; padding:2px 8px; border-radius:10px; font-size:11px; margin:2px;">${t}</span>`).join('') : '';
    const contract = offer.contract_type ? `<span style="color:#666; font-size:12px;">${offer.contract_type}</span>` : '';
    const location = offer.location ? ` - <span style="color:#666; font-size:12px;">${offer.location}</span>` : '';

    html += `
    <tr style="border-bottom: 1px solid #eee;">
      <td style="padding: 12px 8px;">
        <div style="font-weight: bold; font-size: 15px;">${offer.title || 'Offre sans titre'}</div>
        <div style="font-size: 12px; color: #555; margin: 4px 0;">${contract}${location}</div>
        <div style="font-size: 12px; color: #888;">${offer.summary || ''}</div>
        <div style="margin-top: 6px;">${tags}</div>
      </td>
    </tr>`;
  });

  html += `</table>`;
}

html += `
<div style="margin-top: 30px; padding: 15px; background: #f9f9f9; border-radius: 8px; font-size: 12px; color: #666;">
  <p>Veille automatisee generee par Talentsphere · n8n + GPT</p>
  <p>Pour vous desabonner, repondez STOP a cet email.</p>
</div>
</body></html>`;

return [{ json: { html, subject: `Veille Emploi Media — ${dateStr}`, offerCount: items.length } }];
